### 朴素Dijkstra算法

时间复杂度：O(n^2 + m), 其中 n 表示点数，m 表示边数

**https://oi-wiki.org/graph/shortest-path/#dijkstra-%E7%AE%97%E6%B3%95**

```java
    static int n;
    static int[][] g = new int[n + 1][n + 1]; // 存储每条边
    static int[] dist = new int[n + 1]; // 存储1号点到每个点的最短距离
    static boolean[] st = new boolean[n + 1]; // 存储每个点的最短路是否已经确定

    // 求1号点到n号点的最短路，如果不存在则返回-1
    static int dijkstra() {
        Arrays.fill(dist, 0x3f3f3f3f);
        dist[1] = 0;

        for (int i = 0; i < n - 1; i++) {
            int t = -1; // 在还未确定最短路的点中，寻找距离最小的点
            for (int j = 1; j <= n; j++) {
                if (!st[j] && (t == -1 || dist[t] > dist[j])) {
                    t = j;
                }
            }

            // 用t更新其他点的距离
            for (int j = 1; j <= n; j++) {
                dist[j] = Math.min(dist[j], dist[t] + g[t][j]);
            }

            st[t] = true;
        }

        if (dist[n] == 0x3f3f3f3f) {
            return -1;
        }
        return dist[n];
    }
```

### SPFA算法（队列优化的Bellman-Ford算法）

时间复杂度：平均情况下 O(m), 最坏情况下 O(nm), 其中 n 表示点数，m 表示边数

**https://oi-wiki.org/graph/shortest-path/#%E9%98%9F%E5%88%97%E4%BC%98%E5%8C%96spfa**

```java
    static int n, m; // 总点数, 总边数
    static int[] h = new int[n + 1];
    static int[] w = new int[m + 1];
    static int[] e = new int[m + 1];
    static int[] ne = new int[m + 1];
    static int[] dist = new int[n + 1]; // 存储每个点到1号点的最短距离
    static boolean[] st = new boolean[n + 1]; // 存储每个点是否在队列中

    // 求1号点到n号点的最短路距离，如果从1号点无法走到n号点则返回-1
    static int spfa() {
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[1] = 0;

        Queue<Integer> q = new LinkedList<>();
        q.offer(1);
        st[1] = true;

        while (!q.isEmpty()) {
            int t = q.poll();
            st[t] = false;

            for (int i = h[t]; i != -1; i = ne[i]) {
                int j = e[i];
                if (dist[j] > dist[t] + w[i]) {
                    dist[j] = dist[t] + w[i];
                    if (!st[j]) { // 如果队列中已存在j，则不需要将j重复插入
                        q.offer(j);
                        st[j] = true;
                    }


                }
            }
        }

        if (dist[n] == Integer.MAX_VALUE) {
            return -1;
        }
        return dist[n];
    }
```

### SPFA判断图中是否存在负环

时间复杂度：O(nm), 其中 n 表示点数，m 表示边数

```java
    static int n, m; // 总点数, 总边数
    static int[] h = new int[n + 1];
    static int[] w = new int[m + 1];
    static int[] e = new int[m + 1];
    static int[] ne = new int[m + 1];
    static int[] dist = new int[n + 1]; // dist[x]存储1号点到x的最短距离
    static int[] cnt = new int[n + 1]; // cnt[x]存储1到x的最短路中经过的点数
    static boolean[] st = new boolean[n + 1]; // 存储每个点是否在队列中

    // 如果存在负环，则返回true，否则返回false。
    static boolean spfa() {
        Queue<Integer> q = new LinkedList<>();
        for (int i = 1; i <= n; i++) {
            q.offer(i);
            st[i] = true;
        }

        while (!q.isEmpty()) {
            int t = q.poll();
            st[t] = false;

            for (int i = h[t]; i != -1; i = ne[i]) {
                int j = e[i];
                if (dist[j] > dist[t] + w[i]) {
                    dist[j] = dist[t] + w[i];
                    cnt[j] = cnt[t] + 1;
                    if (cnt[j] >= n) { // 如果从1号点到x的最短路中包含至少n个点（不包括自己），则说明存在环
                        return true;
                    }
                    if (!st[j]) {
                        q.offer(j);
                        st[j] = true;
                    }
                }
            }
        }

        return false;
    }
```

### Floyd算法

时间复杂度：O(n^3), 其中 n 表示点数

**https://oi-wiki.org/graph/shortest-path/#floyd-%E7%AE%97%E6%B3%95**

```java
    static final int INF = 0x3f3f3f3f;
    static int n; // 总点数
    static int[][] d = new int[n + 1][n + 1]; // 存储最短距离

    // 初始化
    static void init() {
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if (i == j) {
                    d[i][j] = 0;
                } else {
                    d[i][j] = INF;
                }
            }
        }
    }

    // 算法结束后，d[a][b]表示a到b的最短距离
    static void floyd() {
        for (int k = 1; k <= n; k++) {
            for (int i = 1; i <= n; i++) {
                for (int j = 1; j <= n; j++) {
                    d[i][j] = Math.min(d[i][j], d[i][k] + d[k][j]);
                }
            }
        }
    }
```

### 朴素版Prim算法

时间复杂度：O(n^2 + m), 其中 n 表示点数，m 表示边数

**https://oi-wiki.org/graph/mst/#prim-%E7%AE%97%E6%B3%95**

```java
    static final int INF = 0x3f3f3f3f;
    static int n; // n表示点数
    static int[][] g = new int[n + 1][n + 1]; // 邻接矩阵，存储所有边
    static int[] dist = new int[n + 1]; //

    // 存储其他点到当前最小生成树的距离
    static boolean[] st = new boolean[n + 1]; // 存储每个点是否已经在生成树中

    // 如果图不连通，则返回INF(值是0x3f3f3f3f)，否则返回最小生成树的树边权重之和
    static int prim() {
        Arrays.fill(dist, INF);

        int res = 0;
        for (int i = 0; i < n; i++) {
            int t = -1;
            for (int j = 1; j <= n; j++) {
                if (!st[j] && (t == -1 || dist[t] > dist[j])) {
                    t = j;
                }
            }

            if (i != 0 && dist[t] == INF) {
                return INF;
            }

            if (i != 0) {
                res += dist[t];
            }
            st[t] = true;

            for (int j = 1; j <= n; j++) {
                dist[j] = Math.min(dist[j], g[t][j]);
            }
        }

        return res;
    }
```

### Kruskal 算法

时间复杂度：O(m * log(m)), 其中 n 表示点数，m 表示边数

**https://oi-wiki.org/graph/mst/#kruskal-%E7%AE%97%E6%B3%95**

```java
    static int n, m; // n是点数，m是边数
    static int[] p = new int[n + 1];
    static int[][] e = new int[m + 1][3];
    public static int find(int x) { // 并查集核心操作
        if (p[x] != x) {
            p[x] = find(p[x]);
        }
        return p[x];
    }
    public static int kruskal() {
        Arrays.sort(e, 0, m, (o1, o2) -> o1[2] - o2[2]);

        for (int i = 1; i <= n; i++) {
            p[i] = i; // 初始化并查集
        }

        int res = 0, cnt = 0;
        for (int i = 0; i < m; i++) {
            int a = e[i][0], b = e[i][1], w = e[i][2];

            a = find(a);
            b = find(b);
            if (a != b) { // 如果两个连通块不连通，则将这两个连通块合并
                p[a] = b;
                res += w;
                cnt++;
            }
        }
        //没有最小生成树
        if (cnt < n - 1) {
            return Integer.MAX_VALUE;
        }
        return res;
    }
```



