### 线性筛法求素数

**https://oi-wiki.org/math/number-theory/sieve/#%E7%B4%A0%E6%95%B0%E7%AD%9B%E6%B3%95**

```java
    static int n;//求小于等于n的素数
    static int[] primes = new int[n + 1]; // 存储所有素数
    static boolean[] st = new boolean[n + 1]; // 存储x是否被筛掉
    static int cnt = 0;

    static void getPrimes(int n) {
        for (int i = 2; i <= n; i++) {
            if (!st[i]) {
                primes[cnt++] = i;
            }
            for (int j = 0; j < cnt && primes[j] <= n / i; j++) {
                st[primes[j] * i] = true;
                if (i % primes[j] == 0) {
                    break;
                }
            }
        }
    }
```

